//! Test generator for UPLC conformance tests.
//! Walks the tests/conformance directory and generates test functions.

const std = @import("std");

pub fn main() !void {
    const allocator = std.heap.page_allocator;

    // Open the output file
    const output_path = "conformance/tests.zig";
    const file = try std.fs.cwd().createFile(output_path, .{});
    defer file.close();

    var write_buf: [4096]u8 = undefined;
    var writer_obj = file.writer(&write_buf);
    const writer = &writer_obj.interface;

    // Write header
    try writer.writeAll(
        \\//! Auto-generated conformance tests.
        \\//! DO NOT EDIT - generated by build/gen_tests.zig
        \\
        \\const std = @import("std");
        \\const root = @import("plutuz");
        \\const ExBudget = root.cek.ExBudget;
        \\
        \\fn runTest(comptime source_path: []const u8) !void {
        \\    const source = @embedFile(source_path);
        \\    const expected = @embedFile(source_path ++ ".expected");
        \\    const expected_budget = @embedFile(source_path ++ ".budget.expected");
        \\
        \\    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
        \\    defer arena.deinit();
        \\    const allocator = arena.allocator();
        \\
        \\    const expect_parse_error = std.mem.startsWith(u8, expected, "parse error");
        \\    const expect_eval_failure = std.mem.startsWith(u8, expected, "evaluation failure");
        \\
        \\    // Step 1: Parse the program
        \\    const program = root.parse(allocator, source) catch |err| {
        \\        if (expect_parse_error) {
        \\            // Good - we expected a parse error
        \\            return;
        \\        }
        \\        std.debug.print("Parse error in {s}: {}\n", .{ source_path, err });
        \\        return err;
        \\    };
        \\
        \\    if (expect_parse_error) {
        \\        std.debug.print("Expected parse error in {s} but parsing succeeded\n", .{source_path});
        \\        return error.ExpectedParseError;
        \\    }
        \\
        \\    // Step 2: Convert to DeBruijn
        \\    const dProgram = root.nameToDeBruijn(allocator, program) catch |err| {
        \\        if (expect_eval_failure) {
        \\            // Conversion failure counts as evaluation failure
        \\            return;
        \\        }
        \\        std.debug.print("Conversion error in {s}: {}\n", .{ source_path, err });
        \\        return err;
        \\    };
        \\
        \\    // Step 3: Evaluate the program using the CEK machine directly
        \\    const initial_budget = ExBudget.unlimited;
        \\    var machine = root.DeBruijnMachine.init(allocator);
        \\    machine.budget = initial_budget;
        \\
        \\    const result = machine.run(dProgram.term) catch |err| {
        \\        if (expect_eval_failure) {
        \\            // Good - we expected evaluation failure
        \\            return;
        \\        }
        \\        std.debug.print("Evaluation error in {s}: {}\n", .{ source_path, err });
        \\        return err;
        \\    };
        \\
        \\    if (expect_eval_failure) {
        \\        std.debug.print("Expected evaluation failure in {s} but succeeded\n", .{source_path});
        \\        return error.ExpectedEvalFailure;
        \\    }
        \\
        \\    // Step 4: Parse expected result
        \\    const expectedProgram = root.parse(allocator, expected) catch |err| {
        \\        std.debug.print("Failed to parse expected in {s}: {}\n", .{ source_path, err });
        \\        return err;
        \\    };
        \\
        \\    // Step 5: Convert expected to DeBruijn
        \\    const dExpected = root.nameToDeBruijn(allocator, expectedProgram) catch |err| {
        \\        std.debug.print("Failed to convert expected in {s}: {}\n", .{ source_path, err });
        \\        return err;
        \\    };
        \\
        \\    // Step 6: Compare results via pretty printing
        \\    const prettyResult = root.prettyDeBruijnTerm(allocator, result) catch |err| {
        \\        std.debug.print("Failed to pretty print result in {s}: {}\n", .{ source_path, err });
        \\        return err;
        \\    };
        \\
        \\    const prettyExpected = root.prettyDeBruijnTerm(allocator, dExpected.term) catch |err| {
        \\        std.debug.print("Failed to pretty print expected in {s}: {}\n", .{ source_path, err });
        \\        return err;
        \\    };
        \\
        \\    if (!std.mem.eql(u8, prettyResult, prettyExpected)) {
        \\        std.debug.print(
        \\            \\Result mismatch in {s}
        \\            \\Got:
        \\            \\{s}
        \\            \\Want:
        \\            \\{s}
        \\            \\
        \\        , .{ source_path, prettyResult, prettyExpected });
        \\        return error.ResultMismatch;
        \\    }
        \\
        \\    // Step 7: Compare budgets
        \\    const consumed = machine.consumedBudget(initial_budget);
        \\
        \\    // Format: ({cpu: <num>\n| mem: <num>})
        \\    var buf: [128]u8 = undefined;
        \\    const actual_budget = std.fmt.bufPrint(&buf, "({{cpu: {d}\n| mem: {d}}})", .{
        \\        consumed.cpu,
        \\        consumed.mem,
        \\    }) catch unreachable;
        \\
        \\    const trimmed = std.mem.trim(u8, expected_budget, &std.ascii.whitespace);
        \\
        \\    if (!std.mem.eql(u8, actual_budget, trimmed)) {
        \\        std.debug.print(
        \\            \\Budget mismatch in {s}
        \\            \\Got:
        \\            \\{s}
        \\            \\Want:
        \\            \\{s}
        \\            \\
        \\        , .{ source_path, actual_budget, trimmed });
        \\        return error.BudgetMismatch;
        \\    }
        \\}
        \\
        \\
    );

    // Walk the conformance test data directory
    const conformance_dir = "conformance/tests";
    try walkDir(allocator, conformance_dir, writer);

    // No footer needed - tests are imported from root.zig

    try writer.flush();
    std.debug.print("Generated {s}\n", .{output_path});
}

fn walkDir(allocator: std.mem.Allocator, dir_path: []const u8, writer: anytype) !void {
    var dir = std.fs.cwd().openDir(dir_path, .{ .iterate = true }) catch |err| {
        std.debug.print("Warning: Could not open directory {s}: {}\n", .{ dir_path, err });
        return;
    };
    defer dir.close();

    var iter = dir.iterate();
    while (try iter.next()) |entry| {
        const full_path = try std.fs.path.join(allocator, &.{ dir_path, entry.name });
        defer allocator.free(full_path);

        switch (entry.kind) {
            .directory => {
                try walkDir(allocator, full_path, writer);
            },
            .file => {
                if (std.mem.endsWith(u8, entry.name, ".uplc")) {
                    try generateTest(full_path, writer);
                }
            },
            else => {},
        }
    }
}

fn generateTest(file_path: []const u8, writer: anytype) !void {
    // Create test name from path
    var test_name_buf: [512]u8 = undefined;
    var test_name_len: usize = 0;

    // Skip "conformance/tests/" prefix
    const path_start = if (std.mem.indexOf(u8, file_path, "conformance/tests/")) |idx|
        idx + "conformance/tests/".len
    else
        0;

    // Remove .uplc suffix and convert to test name
    const path_without_ext = file_path[path_start .. file_path.len - 5];

    for (path_without_ext) |c| {
        const new_c: u8 = switch (c) {
            '/', '-', '.' => '_',
            else => c,
        };
        if (test_name_len < test_name_buf.len) {
            test_name_buf[test_name_len] = new_c;
            test_name_len += 1;
        }
    }

    const test_name = test_name_buf[0..test_name_len];

    // Write test function
    // Strip "conformance/" prefix since tests.zig is in conformance/
    const rel_path = if (std.mem.startsWith(u8, file_path, "conformance/"))
        file_path["conformance/".len..]
    else
        file_path;
    try writer.print(
        \\test "conformance_{s}" {{
        \\    try runTest("{s}");
        \\}}
        \\
        \\
    , .{ test_name, rel_path });
}
